      { "id": "demons_one_shall_stand", "name": "One Shall Stand", "type": "Prata", "description": "Vanquish Adjudicator without having him fall down", "tip": "Use arco ou magia da parte superior e mire na cabeca sem derrubar o chefe.", "is_missable": true, "is_spoiler": true },
      { "id": "demons_may_you_be_unharmed", "name": "May you be unharmed", "type": "Prata", "description": "Vanquish Maiden Astraea without killing Garl Vinland", "tip": "Derrote Maiden Astraea sem matar Garl Vinland; arco de longe costuma ser o caminho mais seguro.", "is_missable": false, "is_spoiler": true },
      { "id": "demons_seekest_soul_power", "name": "Seekest soul power", "type": "Ouro", "description": "Embrace the power of the Old One", "tip": "Trofeu de final. Use backup se quiser reduzir runs e preservar recursos do final alternativo.", "is_missable": true, "is_spoiler": true },
      { "id": "demons_a_dash_of_sage", "name": "A Dash of Sage", "type": "Bronze", "description": "Rescue Sage Freke the Visionary", "tip": "Resgate Sage Freke em Prison of Hope para liberar parte importante das magias.", "is_missable": false, "is_spoiler": true },
      { "id": "demons_umbasa", "name": "Umbasa", "type": "Bronze", "description": "Rescue Saint Urbain", "tip": "Resgate Saint Urbain em Shrine of Storms para acessar milagres importantes.", "is_missable": false, "is_spoiler": true },
      { "id": "demons_worthy_of_the_sword", "name": "Worthy of the Sword", "type": "Prata", "description": "Deliver Makoto to Satsuki", "tip": "Exige Pure White World Tendency em Shrine of Storms e a entrega correta da Makoto para Satsuki.", "is_missable": true, "is_spoiler": true },
      { "id": "demons_road_to_possibilities", "name": "Road to Possibilities", "type": "Bronze", "description": "Give the Searing Demon Soul to Blacksmith Ed", "tip": "Nao consuma a Searing Demon Soul de Flamelurker; entregue-a a Blacksmith Ed para liberar upgrades de boss souls.", "is_missable": true, "is_spoiler": true },
      { "id": "demons_one_of_the_few", "name": "One of the few", "type": "Prata", "description": "Obtain Istarelle", "tip": "Exige Pure White World Tendency em Valley of Defilement. Controle mortes em forma humana.", "is_missable": true, "is_spoiler": true },
      { "id": "demons_witch_in_the_tower", "name": "Witch in the Tower", "type": "Bronze", "description": "Rescue Yuria the Witch", "tip": "No remake de PS5, use o conjunto completo de Official para acessar Yuria; ela e essencial para magias.", "is_missable": false, "is_spoiler": true },
      { "id": "demons_legacy_of_the_kings", "name": "Legacy of the Kings", "type": "Ouro", "description": "Obtain the Northern Regalia", "tip": "Planeje Soulbrandt, Demonbrandt, False King's Soul, Ostrava/Mausoleum Key e Blacksmith Ed; normalmente fica para NG+.", "is_missable": true, "is_spoiler": true },
      { "id": "demons_sages_trophy", "name": "Sage's Trophy", "type": "Ouro", "description": "All Magic Spells Obtained", "tip": "Todas as magias exigem boss souls e NPCs como Freke e Yuria. Backup/NG+ reduz retrabalho.", "is_missable": true, "is_spoiler": false },
      { "id": "demons_saints_trophy", "name": "Saint's Trophy", "type": "Ouro", "description": "All Miracles Obtained", "tip": "Todos os milagres exigem planejamento de boss souls e acesso a Saint Urbain.", "is_missable": true, "is_spoiler": false },
      { "id": "demons_king_of_rings", "name": "King of Rings", "type": "Ouro", "description": "All Rings Obtained", "tip": "O trofeu mais sensivel a tendencia, NPCs e escolhas. Controle World Tendency e Character Tendency desde cedo.", "is_missable": true, "is_spoiler": false }
