      { "id": "ff16_such_dodge_so_mega", "name": "Such Dodge, So Mega", "type": "Bronze", "description": "Execute 3 Precision Dodges while charging a single Megaflare (excluding battles in the Hall of Virtue).", "tip": "Com Wings of Light ativo, faca tres precision dodges antes de descarregar Megaflare.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_oh_snap", "name": "Oh, Snap!", "type": "Bronze", "description": "Inflict Permafrost on 10 enemies by perfectly dodging attacks with Cold Snap (excluding battles in the Hall of Virtue).", "tip": "Use Cold Snap/Shiva para esquivar no timing perfeito e congelar inimigos.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_cold_blooded", "name": "Cold-blooded", "type": "Bronze", "description": "Simultaneously defeat 3 or more enemies frozen using Frostbite, Permafrost, or Diamond Dust (excluding battles in the Hall of Virtue).", "tip": "Congele um grupo e finalize tres ou mais inimigos ao mesmo tempo.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_every_damn_sinew", "name": "Every Damn Sinew", "type": "Bronze", "description": "Land a Lv. 2 or higher Zantetsuken 5 times (excluding battles in the Hall of Virtue).", "tip": "Carregue Zantetsuken/Odin ate nivel 2+ e acerte cinco usos.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_fistful_of_steel", "name": "Fistful of Steel", "type": "Bronze", "description": "Execute 3 Steel Counters in a single battle (excluding those in the Hall of Virtue).", "tip": "Use Arm of Darkness/Odin e execute Steel Counter tres vezes no mesmo combate.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_yes_eikon", "name": "Yes, Eikon", "type": "Bronze", "description": "Master all of a single Eikon's abilities and feats.", "tip": "Gaste AP para dominar todas as habilidades/feat de um Eikon.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_masterclass", "name": "Masterclass", "type": "Ouro", "description": "Upgrade all feats and abilities to their maximum.", "tip": "Maior grind de AP: domine todas as habilidades e feats. Pode continuar no Final Fantasy Mode/New Game+.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_with_two_ds", "name": "With Two Ds", "type": "Bronze", "description": "Upgrade consumable potency and inventory slots to their maximum.", "tip": "Complete side quests com icone verde/plus para melhorar pocoes e capacidade de inventario.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_and_they_opened_up_my_mind", "name": "And They Opened Up My Mind", "type": "Prata", "description": "Collect six signboards.", "tip": "Signboards sao recompensas de side quests importantes. Limpe side content antes de fechar a campanha/NG+.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_think_mark", "name": "Think, Mark!", "type": "Bronze", "description": "Defeat 10 notorious marks.", "tip": "Use o Hunt Board para derrotar 10 Notorious Marks.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_hunter_hunted", "name": "Hunter, Hunted", "type": "Prata", "description": "Clear the Hunt Board.", "tip": "Derrote todos os Notorious Marks da lista base. Hunts avancadas ajudam com materiais de crafting.", "is_missable": false, "is_spoiler": true },
      { "id": "ff16_trial_run", "name": "Trial Run", "type": "Bronze", "description": "Complete a chronolith trial.", "tip": "Complete qualquer Chronolith Trial; todos entram no caminho de For the Hoard.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_for_the_hoard", "name": "For the Hoard", "type": "Prata", "description": "Obtain all curiosities.", "tip": "Exige as curiosities exibidas no Wall of Memories em Clive's Room, nao todas as curiosities do inventario.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_dressed_to_the_fives", "name": "Dressed to the Fives", "type": "Bronze", "description": "Craft or upgrade 5 pieces of gear.", "tip": "Craft/upgrade cinco equipamentos no Blacksmith.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_half_past_twilight", "name": "Half Past Twilight", "type": "Prata", "description": "Craft the legendary sword Gotterdammerung.", "tip": "Condicionalmente perdivel: nao venda Ragnarok, Orichalcum, Darksteel, Primitive Battlehorn ou materiais raros antes de craftar Gotterdammerung.", "is_missable": true, "is_spoiler": false },
      { "id": "ff16_the_pen_is_mightier", "name": "The Pen Is Mightier", "type": "Bronze", "description": "Open 10 letters at the reading table.", "tip": "Leia 10 cartas em Clive's Room conforme elas chegarem por historia e side quests.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_the_more_you_know", "name": "The More You Know", "type": "Bronze", "description": "Help Harpocrates attain a knowledge level of 5.", "tip": "Converse com Harpocrates no Hideaway conforme avanca historia e side content.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_careful_whisper", "name": "Careful Whisper", "type": "Prata", "description": "Obtain all available items from your patrons.", "tip": "Colete todos os Patron Items aumentando Renown com main quests, side quests e Hunts.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_you_can_pet_the_dog", "name": "You Can Pet the Dog", "type": "Bronze", "description": "Pet Torgal 5 times.", "tip": "Depois que Torgal estiver disponivel, interaja com ele cinco vezes.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_a_fine_hound", "name": "A Fine Hound", "type": "Bronze", "description": "Execute and land 5 Precision Sics (excluding battles in the Hall of Virtue).", "tip": "Comande Torgal para Sic no timing correto durante combates reais.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_when_you_ride_alone", "name": "When You Ride Alone", "type": "Bronze", "description": "Ride Ambrosia for the first time.", "tip": "Complete a side quest The White-Winged Wonder e monte Ambrosia.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_here_be_rosfields", "name": "Here Be Rosfields", "type": "Bronze", "description": "Visit all areas on the world and local maps.", "tip": "Complete main quests e side quests para revelar todas as areas relevantes do mapa.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_eureka", "name": "Eureka", "type": "Bronze", "description": "Spend 36,000 gil at the Tub & Crown.", "tip": "Gaste gil no Tub & Crown; faca save manual antes se quiser recuperar o dinheiro depois.", "is_missable": false, "is_spoiler": false },
      { "id": "ff16_fantasy_finally", "name": "Fantasy, Finally", "type": "Ouro", "description": "Complete the game on \"Final Fantasy\" mode.", "tip": "Final Fantasy Mode libera apos terminar a historia uma vez. Inicie New Game+ com clear save e conclua a campanha novamente.", "is_missable": false, "is_spoiler": false }
