      "coverage_level": "strong",
      "is_verified": false,
      "verification_status": "review",
      "verification_note": "Precisa revisão editorial final: escopo base/Iceborne e online/multiplayer registrados; revisar coroas, eventos e grind antes de selo verificado.",
